def log_crypto_oversold_heuristic_decision(
    today_stats: dict, fired: bool, new_multiplier: float, rationale_lines: list
) -> None:
    """Append a rationale line when heuristic_crypto_oversold_boost fires or skips."""
    rsi_snap = today_stats.get('rsi_snapshot', {})
    eth_rsi = rsi_snap.get('ETH/USD', {}).get('today')
    btc_rsi = rsi_snap.get('BTC/USD', {}).get('today')
    date_str = today_stats.get('as_of', 'unknown')
    if fired:
        msg = (
            f"{date_str} · heuristic_crypto_oversold_boost FIRED: "
            f"ETH={eth_rsi} BTC={btc_rsi} -> size_multiplier={new_multiplier:.2f}"
        )
    else:
        msg = (
            f"{date_str} · heuristic_crypto_oversold_boost SKIPPED: "
            f"ETH={eth_rsi} BTC={btc_rsi} (conditions not met)"
        )
    rationale_lines.append(msg)

