class TestLogCryptoOversoldHeuristicDecision(unittest.TestCase):
    def test_fired_appends_fired_message(self):
        stats = {'rsi_snapshot': {'ETH/USD': {'today': 24.4}, 'BTC/USD': {'today': 34.2}}, 'as_of': '2026-05-22'}
        lines = []
        log_crypto_oversold_heuristic_decision(stats, fired=True, new_multiplier=1.3, rationale_lines=lines)
        self.assertEqual(len(lines), 1)
        self.assertIn('FIRED', lines[0])
        self.assertIn('1.30', lines[0])
    def test_skipped_appends_skipped_message(self):
        stats = {'rsi_snapshot': {'ETH/USD': {'today': 45.0}, 'BTC/USD': {'today': 50.0}}, 'as_of': '2026-05-22'}
        lines = []
        log_crypto_oversold_heuristic_decision(stats, fired=False, new_multiplier=1.0, rationale_lines=lines)
        self.assertEqual(len(lines), 1)
        self.assertIn('SKIPPED', lines[0])
    def test_missing_rsi_does_not_crash(self):
        stats = {'as_of': '2026-05-22'}
        lines = []
        log_crypto_oversold_heuristic_decision(stats, fired=False, new_multiplier=1.0, rationale_lines=lines)
        self.assertEqual(len(lines), 1)
